// Replicate the segmentation logic from Next.js /api/events/[id]/followup
// Output: 4 items, one per segment, each with { segment, webhookUrl, payload }
const eventArr = $('Supabase – Fetch Event').all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]);
const event = eventArr[0] || {};
const attendeeRsvps = $('Supabase – Fetch Attended RSVPs').all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]);
const contacts = $('Supabase – Fetch Contact Details').all().flatMap(i => Array.isArray(i.json) ? i.json : [i.json]);

const contactMap = new Map(contacts.map(c => [c.id, c]));

// Segment rules matching Next.js route
const speakerTypes = new Set(['speaker']);
const sponsorTypes = new Set(['sponsor', 'partner']);

const allAttendedContactIds = attendeeRsvps.map(r => r.contact_id);
const eventId = event.id || $('Dispatch Webhook').first().json.eventId;

const groups = { new_attendee: [], returning_attendee: [], speaker: [], sponsor: [] };

for (const rsvp of attendeeRsvps) {
  const contact = contactMap.get(rsvp.contact_id);
  if (!contact || !contact.email) continue;

  let segment;
  if (sponsorTypes.has(contact.type)) segment = 'sponsor';
  else if (speakerTypes.has(contact.type)) segment = 'speaker';
  else segment = 'new_attendee'; // Supabase fallback: assume new (no attendance history here)

  groups[segment].push({ id: contact.id, name: contact.name, email: contact.email });
}

const segmentToEnvUrl = {
  new_attendee: $env.N8N_FOLLOWUP_NEW_ATTENDEE_URL,
  returning_attendee: $env.N8N_FOLLOWUP_RETURNING_ATTENDEE_URL,
  speaker: $env.N8N_FOLLOWUP_SPEAKER_URL,
  sponsor: $env.N8N_FOLLOWUP_SPONSOR_URL,
};

const segmentLabels = {
  new_attendee: 'New Attendee',
  returning_attendee: 'Returning Attendee',
  speaker: 'Speaker',
  sponsor: 'Sponsor / Partner',
};

// Build one output item per segment that has attendees
const outputs = [];
for (const [segment, attendees] of Object.entries(groups)) {
  if (attendees.length === 0) continue;
  const webhookUrl = segmentToEnvUrl[segment];
  if (!webhookUrl) continue;
  outputs.push({
    json: {
      webhookUrl,
      payload: {
        event: { id: event.id, title: event.title, event_date: event.event_date },
        sequence: { segment, label: segmentLabels[segment], steps: [] },
        attendees,
        triggered_at: new Date().toISOString(),
      }
    }
  });
}

return outputs;
